import subprocess

def convertDocument(input_file, output_file, output_format):
    if output_format == 'pdf':
        cmd = f"libreoffice --headless --convert-to pdf {input_file} && mv *.pdf {output_file}"
    elif output_format == 'docx':
        cmd = f"libreoffice --headless --convert-to docx {input_file} && mv *.docx {output_file}"
    elif output_format == 'odt':
        cmd = f"libreoffice --headless --convert-to odt {input_file} && mv *.odt {output_file}"
    else:
        print("Unsupported format")
        return
    
    try:
        subprocess.run(cmd, shell=True)
    except Exception as e:
        print(f"Error converting document: {e}")

# Example usage
convertDocument('input.docx', 'output.pdf', 'pdf')